const dmg = require\('./src/ro_damage_formulas'\);

// Test critical path
console.log\('=== Critical Path Test ==='\);
const atkStats = { str: 50, agi: 30, vit: 10, int: 5, dex: 40, luk: 80, level: 99, weaponATK: 120 };
const defStats = { str: 10, agi: 10, vit: 40, int: 5, dex: 10, luk: 3, level: 50 };
let critCount = 0, hitCount = 0, dodgeCount = 0, perfectDodgeCount = 0, missCount = 0;
const N = 5000;
for \(let i = 0; i < N; i++\) {
    const r = dmg.calculatePhysicalDamage\(
        { stats: atkStats, weaponATK: 120, weaponType: 'sword', weaponElement: 'fire', weaponLevel: 3, buffMods: { atkMultiplier: 1.0 } },
        { stats: defStats, hardDef: 30, element: { type: 'earth', level: 1 }, size: 'medium', race: 'brute', numAttackers: 1, buffMods: { defMultiplier: 1.0 } },
        {}
    \);
    if \(r.hitType === 'critical'\) critCount++;
    else if \(r.hitType === 'normal'\) hitCount++;
    else if \(r.hitType === 'dodge'\) dodgeCount++;
    else if \(r.hitType === 'perfectDodge'\) perfectDodgeCount++;
    else if \(r.hitType === 'miss'\) missCount++;
}
console.log\('Over', N, 'attacks:'\);
console.log\('  Normal hits:', hitCount, '\(' + \(hitCount/N*100\).toFixed\(1\) + '%\)'\);
console.log\('  Criticals:', critCount, '\(' + \(critCount/N*100\).toFixed\(1\) + '%\)'\);
console.log\('  Dodges:', dodgeCount, '\(' + \(dodgeCount/N*100\).toFixed\(1\) + '%\)'\);
console.log\('  Perfect Dodges:', perfectDodgeCount, '\(' + \(perfectDodgeCount/N*100\).toFixed\(1\) + '%\)'\);
console.log\('  Misses:', missCount, '\(' + \(missCount/N*100\).toFixed\(1\) + '%\)'\);

// Expected crit rate: 1 + floor\(80*0.3\) + 0 - floor\(3*0.2\) = 1 + 24 - 0 = 25%
console.log\('  Expected crit rate: ~25% \(LUK 80, target LUK 3\)'\);
// Expected perfect dodge: target LUK 3 -> PD = 1 + floor\(3/10\) = 1 => 1%
console.log\('  Expected PD rate: ~1%'\);

// Test element tinting scenario
console.log\('\\n=== Fire vs Earth \(150% bonus\) ==='\);
const fireEarthResult = dmg.calculatePhysicalDamage\(
    { stats: { str: 30, agi: 20, vit: 10, int: 5, dex: 25, luk: 5, level: 50, weaponATK: 80 }, weaponType: 'sword', weaponElement: 'fire', weaponLevel: 2, buffMods: { atkMultiplier: 1.0 } },
    { stats: { str: 5, agi: 5, vit: 10, int: 5, dex: 5, luk: 1, level: 20 }, hardDef: 5, element: { type: 'earth', level: 1 }, size: 'medium', race: 'brute', numAttackers: 1, buffMods: { defMultiplier: 1.0 } },
    {}
\);
console.log\('Damage:', fireEarthResult.damage, 'Element:', fireEarthResult.element, 'ElementMod:', fireEarthResult.elementModifier\);

// Test magical damage
console.log\('\\n=== Magical Damage ==='\);
const magResult = dmg.calculateMagicalDamage\(
    { stats: { str: 5, agi: 5, vit: 5, int: 60, dex: 30, luk: 5, level: 80, weaponATK: 0 }, weaponElement: 'water', buffMods: { atkMultiplier: 1.0 } },
    { stats: { str: 5, agi: 5, vit: 10, int: 20, dex: 5, luk: 5, level: 50 }, hardDef: 0, element: { type: 'fire', level: 1 }, size: 'medium', race: 'brute', numAttackers: 1, buffMods: { defMultiplier: 1.0 } },
    { skillMultiplier: 300 }
\);
console.log\('MATK Damage:', magResult.damage, 'HitType:', magResult.hitType, 'Element:', magResult.element\);

console.log\('\\nAll comprehensive tests passed!'\);
